/*
 * Requires:
 *   "a" and "b" are valid pointers to struct file_info.
 *
 * Effects:
 *   Compares two file_info structs by name using strcmp.
 *   Returns negative, zero, or positive for ASCIIbetical ordering.
 */
static int
compare_file_info(const void *a, const void *b)
{
    const struct file_info *fa = (const struct file_info *)a;
    const struct file_info *fb = (const struct file_info *)b;
    return strcmp(fa->name, fb->name);
}

/*
 * Requires:
 *   "input_files" is a valid array of file name strings.
 *   "nfiles" is the number of files in the array.
 *
 * Effects:
 *   Counts characters, words, and/or lines in each file based on flags.
 *   Prints results for each file in ASCIIbetical order.
 *   Prints totals at the end.
 *   Returns 0 on success, 1-255 on error.
 */
static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    (void)test_flag;

    int error_flag = 0;
    struct counts total = {0, 0, 0};

    /* Allocate array of file_info for sorting */
    struct file_info *files = malloc(nfiles * sizeof(struct file_info));
    if (files == NULL) {
        fprintf(stderr, "ERROR: out of memory\n");
        return 1;
    }

    /* Process each file in input order (errors printed in this order) */
    for (int i = 0; i < nfiles; i++) {
        files[i].name = input_files[i];
        files[i].cnts.chars = 0;
        files[i].cnts.words = 0;
        files[i].cnts.lines = 0;
        files[i].valid = true;

        FILE *fp = fopen(input_files[i], "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            files[i].valid = false;
            error_flag = 1;
            continue;
        }

        /* Single-pass counting */
        int c;
        bool in_word = false;
        while ((c = fgetc(fp)) != EOF) {
            files[i].cnts.chars++;
            if (c == '\n')
                files[i].cnts.lines++;
            if (isspace(c)) {
                in_word = false;
            } else if (!in_word) {
                files[i].cnts.words++;
                in_word = true;
            }
        }

        if (ferror(fp)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            files[i].valid = false;
            error_flag = 1;
        }

        fclose(fp);
    }

    /* Sort by filename (ASCIIbetical order) */
    qsort(files, nfiles, sizeof(struct file_info), compare_file_info);

    /* Print results in sorted order and accumulate totals */
    for (int i = 0; i < nfiles; i++) {
        if (!files[i].valid)
            continue;
        print_counts(stdout, &files[i].cnts, files[i].name,
            char_flag, word_flag, line_flag);
        if (char_flag)
            total.chars += files[i].cnts.chars;
        if (word_flag)
            total.words += files[i].cnts.words;
        if (line_flag)
            total.lines += files[i].cnts.lines;
    }

    /* Print total — always with all three counts */
    print_counts(stdout, &total, "total", true, true, true);

    free(files);
    return error_flag;
}

